  '';

const WORDS = new Set<string>();
for (let i = 0; i < PACKED.length; i += 5) WORDS.add(PACKED.slice(i, i + 5));

export function isValidWord(word: unknown): boolean {
  return typeof word === "string" && /^[A-Z]{5}$/.test(word) && WORDS.has(word);
}

export function randomWord(): string {
  const i = Math.floor(Math.random() * (PACKED.length / 5)) * 5;
  return PACKED.slice(i, i + 5);
}

export function wordCount(): number {
  return PACKED.length / 5;
}
